patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..8aa379bd9352 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7767,10 +7767,54 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,

 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
-  Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
+  Value *X = nullptr;
+  // Try matching fabs intrinsic first
+  if (match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // X is already set
+  }
+  // Try matching select pattern: select (fcmp oge X, 0), X, fneg X  (fabs via select)
+  else if (SelectInst *SI = dyn_cast<SelectInst>(I.getOperand(0))) {
+    Value *CondVal = SI->getCondition();
+    Value *TrueVal = SI->getTrueValue();
+    Value *FalseVal = SI->getFalseValue();
+    
+    if (FCmpInst *FCmp = dyn_cast<FCmpInst>(CondVal)) {
+      Value *Op0 = FCmp->getOperand(0);
+      Value *Op1 = FCmp->getOperand(1);
+      FCmpInst::Predicate Pred = FCmp->getPredicate();
+      Value *XFromFNeg;
+      
+      // Pattern 1: select (fcmp oge X, 0.0), X, fneg X
+      if (Pred == FCmpInst::FCMP_OGE && match(Op1, m_PosZeroFP()) &&
+          TrueVal == Op0 && match(FalseVal, m_FNeg(m_Value(XFromFNeg))) && XFromFNeg == Op0) {
+        X = Op0;
+      }
+      // Pattern 2: select (fcmp olt X, 0.0), fneg X, X
+      else if (Pred == FCmpInst::FCMP_OLT && match(Op1, m_PosZeroFP()) &&
+               FalseVal == Op0 && match(TrueVal, m_FNeg(m_Value(XFromFNeg))) && XFromFNeg == Op0) {
+        X = Op0;
+      }
+      // Pattern 3: select (fcmp oge 0.0, X), fneg X, X  (0 >= X means X <= 0, return -X)
+      else if (Pred == FCmpInst::FCMP_OGE && match(Op0, m_PosZeroFP()) &&
+               FalseVal == Op1 && match(TrueVal, m_FNeg(m_Value(XFromFNeg))) && XFromFNeg == Op1) {
+        X = Op1;
+      }
+      // Pattern 4: select (fcmp olt 0.0, X), X, fneg X  (0 < X means X > 0, return X)
+      else if (Pred == FCmpInst::FCMP_OLT && match(Op0, m_PosZeroFP()) &&
+               TrueVal == Op1 && match(FalseVal, m_FNeg(m_Value(XFromFNeg))) && XFromFNeg == Op1) {
+        X = Op1;
+      }
+      else {
+        return nullptr;
+      }
+    }
+    else {
+      return nullptr;
+    }
+  }
+  else {
     return nullptr;
-
+  }
   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))
     return nullptr;
@@ -7886,6 +7930,11 @@ static Instruction *foldFCmpFNegCommonOp(FCmpInst &I) {
 }

 Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
+  // Try to optimize fabs(X) compared with zero before operand swapping,
+  // because the pattern matching expects the fabs/select on operand 0.
+  if (Instruction *R = foldFabsWithFcmpZero(I, *this))
+    return R;
+
   bool Changed = false;

   /// Orders the operands of the compare so that they are listed from most
@@ -8068,9 +8117,6 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   }
   }

-  if (Instruction *R = foldFabsWithFcmpZero(I, *this))
-    return R;
-
   if (match(Op0, m_FNeg(m_Value(X)))) {
     // fcmp pred (fneg X), C --> fcmp swap(pred) X, -C
     Constant *C;

